var numberOfSubstrings = function(s) {
    const n = s.length;
    const zeroPos = [];
    for (let i = 0; i < n; i++) if (s[i] === '0') zeroPos.push(i);
    const m = zeroPos.length;
    let total = 0;
    let run = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === '1') {
            run += 1;
            total += run;
        } else {
            run = 0;
        }
    }
    function countAtLeast(A, B, need) {
        const totalPairs = (A + 1) * (B + 1);
        const t = need - 1;
        if (t < 0) return totalPairs;
        if (t >= A + B) return 0;
        const upperA = Math.min(A, t);
        const a0 = Math.min(upperA, t - B);
        let cntLe = 0;
        let start2 = 0;
        if (a0 >= 0) {
            cntLe += (a0 + 1) * (B + 1);
            start2 = a0 + 1;
        }
        if (start2 <= upperA) {
            const cnt2 = upperA - start2 + 1;
            const firstVal = t - start2 + 1;
            const lastVal = t - upperA + 1;
            cntLe += cnt2 * (firstVal + lastVal) / 2;
        }
        return totalPairs - cntLe;
    }
    let z = 1;
    while (z * z <= n && z <= m) {
        for (let i = 0; i <= m - z; i++) {
            const leftZero = zeroPos[i];
            const rightZero = zeroPos[i + z - 1];
            const prevZero = i > 0 ? zeroPos[i - 1] : -1;
            const nextZero = i + z < m ? zeroPos[i + z] : n;
            const leftAvail = leftZero - prevZero - 1;
            const rightAvail = nextZero - rightZero - 1;
            const fixedOnes = rightZero - leftZero - (z - 1);
            const need = z * z - fixedOnes;
            if (need <= 0) {
                total += (leftAvail + 1) * (rightAvail + 1);
            } else {
                total += countAtLeast(leftAvail, rightAvail, need);
            }
        }
        z += 1;
    }
    return total;
};
